// // This register loads data on the falling edge of the clock when the load signal is high.
module parallel_load_reg(
    input clk,
    input reset,
    input load,
    input [7:0] data_in,
    output reg [7:0] data_out);always @(posedge clk) begin
    if (reset)
        data_out <= 8'b0;
    else if (load)
        data_out <= data_in;
end
endmodule
